// pages/LearnPage.jsx
// The core Learn page. Triggered when user clicks a topic.
// Fetches AI content from /api/learn and renders 6 structured sections:
//   Concept → Formulas → Shortcuts → Examples → Practice → Summary

import React, { useEffect, useState } from "react";
import { useParams, Link } from "react-router-dom";
import { useLearn } from "../hooks/useLearn";
import { getTopicBySlug } from "../data/topicsData";

// ── Loading skeleton ────────────────────────────────────────
function Skeleton() {
  return (
    <div className="space-y-4 animate-pulse">
      {[180, 120, 100, 160, 140, 110].map((h, i) => (
        <div
          key={i}
          className="rounded-2xl"
          style={{
            height: h,
            background: "rgba(255,255,255,0.04)",
            border: "1px solid rgba(255,255,255,0.06)",
          }}
        />
      ))}
    </div>
  );
}

// ── Section wrapper — consistent glass panel ────────────────
function Section({ label, icon, children, delay = 0 }) {
  return (
    <section
      className="glass animate-fade-up mb-5"
      style={{ animationDelay: `${delay}s` }}
    >
      {/* Section header */}
      <div
        className="flex items-center gap-2.5 px-6 py-3.5"
        style={{ borderBottom: "1px solid rgba(255,255,255,0.05)" }}
      >
        <span style={{ fontSize: "0.85rem" }}>{icon}</span>
        <span className="section-label">{label}</span>
      </div>
      <div className="px-6 py-5">{children}</div>
    </section>
  );
}

// ── Concept section ─────────────────────────────────────────
function ConceptSection({ concept }) {
  return (
    <Section label="Concept" icon="📖" delay={0.05}>
      <p className="text-slate-300 text-sm leading-relaxed">{concept}</p>
    </Section>
  );
}

// ── Formulas section ────────────────────────────────────────
function FormulasSection({ formulas }) {
  return (
    <Section label="Key Formulas" icon="📐" delay={0.10}>
      <div className="space-y-2.5">
        {formulas.map((formula, i) => (
          <div
            key={i}
            className="flex items-start gap-3 p-3.5 rounded-xl"
            style={{
              background: "rgba(99,102,241,0.07)",
              border: "1px solid rgba(99,102,241,0.14)",
            }}
          >
            {/* Index pill */}
            <span
              className="shrink-0 w-5 h-5 rounded-md flex items-center justify-center text-xs font-mono font-bold"
              style={{ background: "rgba(99,102,241,0.25)", color: "#818cf8" }}
            >
              {i + 1}
            </span>
            <code className="text-sm text-indigo-200 font-mono leading-relaxed">
              {formula}
            </code>
          </div>
        ))}
      </div>
    </Section>
  );
}

// ── Shortcuts section ───────────────────────────────────────
function ShortcutsSection({ shortcuts }) {
  return (
    <Section label="Shortcuts & Tips" icon="⚡" delay={0.15}>
      <ul className="space-y-0 list-none m-0 p-0">
        {shortcuts.map((tip, i) => (
          <li
            key={i}
            className="flex items-start gap-3 py-2.5"
            style={{ borderBottom: "1px solid rgba(255,255,255,0.04)" }}
          >
            <span className="shrink-0 text-sm" style={{ color: "#38bdf8" }}>›</span>
            <p className="text-sm text-slate-300 leading-relaxed">{tip}</p>
          </li>
        ))}
      </ul>
    </Section>
  );
}

// ── Examples section ────────────────────────────────────────
function ExamplesSection({ examples }) {
  return (
    <Section label="Solved Examples" icon="✏️" delay={0.20}>
      <div className="space-y-6">
        {examples.map((ex, i) => (
          <div key={i}>
            {/* Question */}
            <div className="flex items-start gap-3 mb-3">
              <span
                className="shrink-0 text-xs font-mono font-bold px-2 py-0.5 rounded-md mt-0.5"
                style={{
                  background: "rgba(56,189,248,0.12)",
                  color: "#38bdf8",
                  border: "1px solid rgba(56,189,248,0.20)",
                }}
              >
                Q{i + 1}
              </span>
              <p className="text-sm text-slate-200 font-medium leading-relaxed">
                {ex.question}
              </p>
            </div>

            {/* Solution */}
            <div
              className="ml-8 p-4 rounded-xl text-sm text-slate-400 leading-relaxed"
              style={{
                background: "rgba(255,255,255,0.03)",
                border: "1px solid rgba(255,255,255,0.06)",
                whiteSpace: "pre-line",
              }}
            >
              {ex.solution}
            </div>

            {/* Divider between examples */}
            {i < examples.length - 1 && (
              <hr className="mt-5 border-t border-white/5" />
            )}
          </div>
        ))}
      </div>
    </Section>
  );
}

// ── Practice question item (show/hide answer) ───────────────
function PracticeItem({ item, index }) {
  const [shown, setShown] = useState(false);

  return (
    <div
      className="py-4"
      style={{ borderBottom: "1px solid rgba(255,255,255,0.05)" }}
    >
      {/* Question row */}
      <div className="flex items-start justify-between gap-4">
        <div className="flex items-start gap-3 flex-1">
          <span
            className="shrink-0 text-xs font-mono font-bold px-2 py-0.5 rounded-md mt-0.5"
            style={{
              background: "rgba(99,102,241,0.12)",
              color: "#a5b4fc",
              border: "1px solid rgba(99,102,241,0.20)",
            }}
          >
            {index + 1}
          </span>
          <p className="text-sm text-slate-300 leading-relaxed">{item.question}</p>
        </div>

        {/* Toggle button */}
        <button
          onClick={() => setShown((v) => !v)}
          className="shrink-0 text-xs px-3 py-1.5 rounded-lg transition-all duration-200"
          style={{
            background: shown ? "rgba(99,102,241,0.15)" : "rgba(255,255,255,0.04)",
            color: shown ? "#a5b4fc" : "#64748b",
            border: shown
              ? "1px solid rgba(99,102,241,0.25)"
              : "1px solid rgba(255,255,255,0.07)",
          }}
        >
          {shown ? "Hide" : "Show Answer"}
        </button>
      </div>

      {/* Answer — revealed on toggle */}
      {shown && (
        <div
          className="mt-3 ml-8 px-4 py-3 rounded-xl text-sm text-slate-300 leading-relaxed animate-fade-in"
          style={{
            background: "rgba(99,102,241,0.07)",
            border: "1px solid rgba(99,102,241,0.15)",
          }}
        >
          <span className="text-xs font-mono text-indigo-400 block mb-1">Answer</span>
          {item.answer}
        </div>
      )}
    </div>
  );
}

function PracticeSection({ practice }) {
  return (
    <Section label="Practice Questions" icon="🎯" delay={0.25}>
      <p className="text-xs text-slate-500 mb-4">
        {practice.length} questions — click "Show Answer" to reveal
      </p>
      <div>
        {practice.map((item, i) => (
          <PracticeItem key={i} item={item} index={i} />
        ))}
      </div>
    </Section>
  );
}

// ── Summary section ─────────────────────────────────────────
function SummarySection({ summary }) {
  return (
    <Section label="Quick Summary" icon="📋" delay={0.30}>
      <div className="space-y-5">
        {/* Key points */}
        <div>
          <p className="text-xs font-mono text-slate-500 uppercase tracking-widest mb-3">
            Key Points
          </p>
          <ul className="space-y-2 list-none m-0 p-0">
            {summary.points.map((pt, i) => (
              <li key={i} className="flex items-start gap-2 text-sm text-slate-300">
                <span className="shrink-0 mt-1 w-1.5 h-1.5 rounded-full bg-indigo-500" />
                {pt}
              </li>
            ))}
          </ul>
        </div>

        {/* Must-remember formulas */}
        <div>
          <p className="text-xs font-mono text-slate-500 uppercase tracking-widest mb-3">
            Must-Remember Formulas
          </p>
          <div className="space-y-2">
            {summary.formulas.map((f, i) => (
              <div
                key={i}
                className="px-3 py-2 rounded-lg text-sm font-mono text-indigo-200"
                style={{
                  background: "rgba(99,102,241,0.07)",
                  border: "1px solid rgba(99,102,241,0.13)",
                }}
              >
                {f}
              </div>
            ))}
          </div>
        </div>

        {/* Best shortcut */}
        <div
          className="p-4 rounded-xl"
          style={{
            background: "rgba(56,189,248,0.06)",
            border: "1px solid rgba(56,189,248,0.14)",
          }}
        >
          <p className="text-xs font-mono text-sky-500 mb-1.5">⚡ Best Shortcut</p>
          <p className="text-sm text-sky-200 leading-relaxed">{summary.shortcut}</p>
        </div>
      </div>
    </Section>
  );
}

// ── Error panel ─────────────────────────────────────────────
function ErrorPanel({ message, onRetry }) {
  return (
    <div
      className="glass p-6 text-center"
      style={{ border: "1px solid rgba(239,68,68,0.20)" }}
    >
      <p className="text-sm text-red-300 mb-1">Failed to load content</p>
      <p
        className="text-xs mb-4 px-3 py-2 rounded-lg inline-block"
        style={{ background: "rgba(239,68,68,0.08)", color: "#fca5a5" }}
      >
        {message}
      </p>
      <br />
      <button onClick={onRetry} className="btn-primary" style={{ fontSize: "0.8rem", padding: "8px 20px" }}>
        Try Again
      </button>
    </div>
  );
}

// ── Main LearnPage ──────────────────────────────────────────
export default function LearnPage() {
  const { topicName }  = useParams();
  const localTopic     = getTopicBySlug(topicName);
  const displayName    = localTopic?.name || topicName?.replace(/-/g, " ");

  const { fetchLearnContent, loading, error } = useLearn();
  const [content, setContent] = useState(null);
  const [retryKey, setRetryKey] = useState(0); // increment to trigger re-fetch

  // Fetch on mount and on retry
  useEffect(() => {
    if (!displayName) return;
    setContent(null); // clear stale content before re-fetch
    fetchLearnContent(displayName).then((data) => {
      if (data) setContent(data);
    });
  }, [displayName, retryKey]); // eslint-disable-line

  const handleRetry = () => setRetryKey((k) => k + 1);

  return (
    <main className="max-w-3xl mx-auto px-5 py-10">

      {/* Breadcrumb */}
      <div className="flex items-center gap-2 text-xs text-slate-500 mb-8 animate-fade-in">
        <Link to="/" className="hover:text-slate-300 transition-colors no-underline">
          Home
        </Link>
        <span>/</span>
        <span className="text-slate-300">{displayName}</span>
      </div>

      {/* Page title */}
      <div className="mb-8 animate-fade-up">
        <h1
          className="text-2xl font-bold text-white mb-1"
          style={{ letterSpacing: "-0.01em" }}
        >
          {displayName}
        </h1>
        {localTopic && (
          <span className="section-label" style={{ color: "#6366f1" }}>
            {localTopic.category}
          </span>
        )}
      </div>

      {/* ── States ── */}
      {loading && <Skeleton />}

      {!loading && error && (
        <ErrorPanel message={error} onRetry={handleRetry} />
      )}

      {!loading && !error && content && (
        <>
          <ConceptSection   concept={content.concept} />
          <FormulasSection  formulas={content.formulas} />
          <ShortcutsSection shortcuts={content.shortcuts} />
          <ExamplesSection  examples={content.examples} />
          <PracticeSection  practice={content.practice} />
          <SummarySection   summary={content.summary} />
        </>
      )}

      {/* Back link */}
      <div className="mt-6">
        <Link
          to="/"
          className="text-xs text-slate-500 hover:text-slate-300 transition-colors no-underline"
        >
          ← Back to all topics
        </Link>
      </div>

      <div className="h-16" />
    </main>
  );
}
